    "id": 37,
    "slug": "webb-hubble-capture-new-views-of-saturn",
    "cat": "Ciências da Terra",
    "catCls": "terra",
    "img": "https://www.esa.int/var/esa/storage/images/esa_multimedia/images/2026/03/saturn_2024_webb_and_hubble_images/27170885-1-eng-GB/Saturn_2024_Webb_and_Hubble_images_pillars.jpg",
